std::vector<BYTE> buf(1 << 20);
DWORD out = 0;
DeviceIoControl(hDrv, IOCTL_ENUM_PROCESSES,
    nullptr, 0, buf.data(), (DWORD)buf.size(), &out, nullptr);
auto* hdr = (PROCESS_LIST_HEADER*)buf.data();
auto* procs = (PROCESS_INFO*)(hdr + 1);
for (ULONG i = 0; i < hdr->Count; i++)
    wprintf(L"PID=%-6lu %s\n", procs[i].ProcessId, procs[i].ImageName);

PROCESS_REQUEST req{ targetPid };
std::vector<BYTE> buf(1 << 16);
DWORD out = 0;
DeviceIoControl(hDrv, IOCTL_ENUM_THREADS,
    &req, sizeof(req), buf.data(), (DWORD)buf.size(), &out, nullptr);
auto* hdr = (THREAD_LIST_HEADER*)buf.data();
auto* threads = (THREAD_INFO*)(hdr + 1);
for (ULONG i = 0; i < hdr->Count; i++)
    printf("TID=%-6lu  prio=%d  start=%016llX\n",
        threads[i].ThreadId, threads[i].Priority, threads[i].StartAddress);

PROCESS_REQUEST req{ targetPid };
DWORD out = 0;
// 隐藏
DeviceIoControl(hDrv, IOCTL_HIDE_PROCESS,
    &req, sizeof(req), nullptr, 0, &out, nullptr);
// 恢复
DeviceIoControl(hDrv, IOCTL_UNHIDE_PROCESS,
    &req, sizeof(req), nullptr, 0, &out, nullptr);

INJECT_DLL_REQUEST req{};
req.ProcessId = targetPid;
wcscpy_s(req.DllPath, L"C:\\tools\\payload.dll");
DWORD out = 0;
// 当前 dispatch 默认返回 STATUS_NOT_SUPPORTED
DeviceIoControl(hDrv, IOCTL_INJECT_DLL,
    &req, sizeof(req), nullptr, 0, &out, nullptr);

// 1. 枚举句柄，找到目标文件路径对应的句柄
HANDLE_ENUM_REQUEST enumReq{ 0 };  // 0 = 全系统
std::vector<BYTE> buf(8 << 20);
DWORD out = 0;
DeviceIoControl(hDrv, IOCTL_ENUM_HANDLES,
    &enumReq, sizeof(enumReq), buf.data(), (DWORD)buf.size(), &out, nullptr);

// 2. 关闭找到的句柄
CLOSE_HANDLE_REQUEST closeReq{ targetPid, handleValue };
DeviceIoControl(hDrv, IOCTL_CLOSE_HANDLE,
    &closeReq, sizeof(closeReq), nullptr, 0, &out, nullptr);

DRIVER_SERVICE_REQUEST req{};
wcscpy_s(req.ServiceName, L"BadDriver");  // 不用加 .sys
DWORD out = 0;
DeviceIoControl(hDrv, IOCTL_UNLOAD_DRIVER,
    &req, sizeof(req), nullptr, 0, &out, nullptr);
